import{c as t,Q as o,j as a,m as i}from"./chunks/framework.CTNaDwNv.js";const h=JSON.parse('{"title":"Scaffold a new resource","description":"","frontmatter":{},"headers":[],"relativePath":"guide/scaffold.md","filePath":"guide/scaffold.md","lastUpdated":1779853631000}'),n={name:"guide/scaffold.md"};function s(l,e,r,d,c,p){return o(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="scaffold-a-new-resource" tabindex="-1">Scaffold a new resource <a class="header-anchor" href="#scaffold-a-new-resource" aria-label="Permalink to &quot;Scaffold a new resource&quot;">​</a></h1><p>The fastest way to produce a non-trivial new FiveM resource through an agent is to invoke the <strong>grill workflow</strong>. It forces the agent to ask every architectural question before any file is written.</p><h2 id="triggering-the-workflow" tabindex="-1">Triggering the workflow <a class="header-anchor" href="#triggering-the-workflow" aria-label="Permalink to &quot;Triggering the workflow&quot;">​</a></h2><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-u6ZI2" id="tab-xUMvmpc" checked><label data-title="Claude Code (slash)" for="tab-xUMvmpc">Claude Code (slash)</label><input type="radio" name="group-u6ZI2" id="tab-EPpVirB"><label data-title="Any client (intent)" for="tab-EPpVirB">Any client (intent)</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; /agent_api:scaffold-fivem-resource</span></span></code></pre></div><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&gt; สร้าง resource ใหม่ที่...</span></span>
<span class="line"><span>&gt; create a new fivem resource for ...</span></span>
<span class="line"><span>&gt; build a script that ...</span></span></code></pre></div></div></div><p>The intent-detection path works in every client. The slash-command path is Claude Code only (other clients don&#39;t surface MCP prompts).</p><h2 id="what-the-agent-will-do" tabindex="-1">What the agent will do <a class="header-anchor" href="#what-the-agent-will-do" aria-label="Permalink to &quot;What the agent will do&quot;">​</a></h2><p>It cannot skip steps — its mandatory contract is loaded into context. Question tree in order:</p><ol><li><strong>Identity</strong> — name, description, author</li><li><strong>Layout</strong> — one file vs multi-file with <code>server/</code>, <code>client/</code>, <code>shared/</code>, <code>config/</code> subfolders. Flat layouts forbidden.</li><li><strong>Module style</strong> — globals via manifest vs <code>return {}</code> + <code>lib.require</code> (needs ox_lib)</li><li><strong>Config split</strong> — <code>config/shared.lua</code>, <code>config/client.lua</code>, <code>config/server.lua</code>. The last one stays server-side and is the only safe place for secrets.</li><li><strong>Framework</strong> — standalone, ESX, QBCore, ox_core, multiple</li><li><strong>ox_lib</strong> — yes / no</li><li><strong>oxmysql</strong> — none / yes (+ list of tables to own)</li><li><strong>UI</strong> — none / yes</li><li><strong>UI stack</strong> — pure HTML+JS / Vite framework</li><li><strong>Framework choice</strong> — Vue 3 / React / Svelte / Solid / Preact</li><li><strong>State management</strong> — built-in / Pinia/Zustand/etc / none</li><li><strong>CSS approach</strong> — plain / scoped / Tailwind / UnoCSS</li><li><strong>Animations</strong> — none / CSS transitions / framework transitions / GSAP</li><li><strong>Validation</strong> — none / hand-rolled / Zod/Valibot</li><li><strong>Icons</strong> — none / inline SVG / Lucide / Phosphor</li><li><strong>Open key / command</strong> — F6 + <code>/&lt;name&gt;</code> recommended</li><li><strong>NUI focus model</strong> — modal / overlay / hybrid</li><li><strong>Lifecycle</strong> — start, playerDropped, stop behaviour</li><li><strong>Audit + rate limit</strong> — what to log, what to throttle</li></ol><p>Every question carries a &quot;Recommended:&quot; line so you can type &quot;ok&quot; / &quot;เอา&quot; and move on. To revise a decision before the agent starts writing, say <code>edit &lt;number&gt;</code>.</p><h2 id="then-it-builds" tabindex="-1">Then it builds <a class="header-anchor" href="#then-it-builds" aria-label="Permalink to &quot;Then it builds&quot;">​</a></h2><p>Once you confirm the summary, the agent walks the scaffolding phase:</p><ol><li><code>create_resource</code></li><li><code>refresh_resources</code></li><li>If UI = Vite: <code>run_shell npm create vite ...</code>, <code>run_shell npm install</code>, edit <code>vite.config</code>, <code>run_shell npm run build</code></li><li><code>write_file</code> every Lua / config file (sandbox-checked)</li><li><code>ensure_resource</code></li><li>If state didn&#39;t reach <code>started</code>: <code>tail_console</code>, propose a fix, ask before rewriting</li></ol><p>You see every step. Nothing happens silently.</p>`,13)])])}const u=t(n,[["render",s]]);export{h as __pageData,u as default};
